UPDATE non_conformities SET five_why_analysis = '{"problem": "Giriş kalite kontrolünde ve sahada kabinlerde su kaçağı tespit edildi.", "why1": "Giriş kalite kontrolünde ve sahada kabinlerde su kaçağı tespit edildi.", "why2": "Tedarikçinin üretim sürecinde sızdırmazlık testi uygulanmıyor veya yetersiz uygulanıyor.", "why3": "Tedarikçinin kalite kontrol planında sızdırmazlık testi parametreleri tanımlı değil.", "why4": "Tedarikçi ile yapılan yeterlilik görüşmelerinde bu konu kapsam dışı bırakılmış.", "why5": "Tedarikçi onay sürecinde sızdırmazlık test kriterleri kontrol planına dahil edilmemiştir.", "rootCause": "Tedarikçi onay sürecinde sızdırmazlık test kriterleri kontrol planına dahil edilmemiştir.", "immediateAction": "Tedarikçiyle sızdırmazlık şartnamesini içeren gözden geçirilmiş teknik şartname ve onaylı numune imzalanmalıdır. Mevcut uygunsuz kabinler iade edilmeli.", "preventiveAction": "Tedarikçi kalite planına sızdırmazlık testi zorunlu adım olarak eklenmeli; %100 hidrostatik test veya basınç testi koşulu konulmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Giriş kalite kontrolünde ve sahada kabinlerde su kaçağı tespit edildi.", "man": ["Tedarikçi operatörleri sızdırmazlık kontrolü konusunda eğitilmemiş."], "material": ["Kabin malzemesinde veya conta tasarımında değişiklik yapılmış ve Kademe''ye bildirilmemiş."], "machine": ["Tedarikçide sızdırmazlık test ekipmanı bulunmuyor veya kalibre değil."], "environment": ["Tedarikçi, kabin tipine göre değişen sızdırmazlık gereksinimlerini ölçemiyor."], "measurement": ["Sızdırmazlık kriterleri muayene planında yer almıyor."], "management": ["Tedarikçiye iletilen teknik şartnamede sızdırmazlık gereksinimleri açıkça belirtilmemiş."]}'::jsonb WHERE nc_number = 'DF-2026-001';
UPDATE non_conformities SET five_why_analysis = '{"problem": "11 adet Konveyor Mafsal Civatası girdi kontrolünde reddedildi. Nominal 167 mm, ölçülen 182,54 mm (sapma: +15,5 mm).", "why1": "11 adet Konveyor Mafsal Civatası girdi kontrolünde reddedildi. Nominal 167 mm, ölçülen 182,54 mm (sapma: +15,5 mm).", "why2": "Tedarikçi üretim sonrası boyutsal kontrol yapmıyor.", "why3": "Tedarikçide bu parçaya ait kontrol planı veya çalışma talimatı eksik/yetersiz.", "why4": "Parça üretim prosesi standart dışı bir bağlantı veya kesim adımı içeriyor, prosedür takip edilmiyor.", "why5": "Tedarikçide imalat prosesinde parça kontrolsüz kesim/işleme yapılmakta; ölçü doğrulaması üretim sonunda uygulanmamaktadır.", "rootCause": "Tedarikçide imalat prosesinde parça kontrolsüz kesim/işleme yapılmakta; ölçü doğrulaması üretim sonunda uygulanmamaktadır.", "immediateAction": "11 adet parça iade edilmeli. Tedarikçiden 8D/düzeltici faaliyet ve yeni doğrulanmış parti gönderilmeli.", "preventiveAction": "Tedarikçi kontrol planına parça kodu 37-5000121577 için ölçüm teyit adımı eklenmeli. Tedarikçi değerlendirme puanı güncellenmeli."}'::jsonb, ishikawa_analysis = '{"problem": "11 adet Konveyor Mafsal Civatası girdi kontrolünde reddedildi.", "man": ["Tedarikçide üretim sorumlusu parça boyutunu kontrol etmemiş veya yanlış iş talimatı kullanılmış."], "material": ["Mafsal civatası hammaddesi yanlış ebat kullanılmış."], "machine": ["Ölçüm aleti (kumpas/gönyeli) kalibrasyonu yapılmamış veya doğru kullanılmamış."], "environment": ["Tedarikçide çevresel faktörler (hata yapmayı artıran ergonomi vb.) tanımlanmamış."], "measurement": ["Tedarikçi ölçüm sistemi analizi (MSA) yapılmamış; ölçüm hatası doğrulanmamış."], "management": ["Kontrol planı, bu parça kodu için boyutsal kontrol adımı içermiyor."]}'::jsonb WHERE nc_number = 'DF-2026-003';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Müşteri şikayeti üzerine incelenen parça fonksiyonel testlerde kaçak verdi.", "why1": "Müşteri şikayeti üzerine incelenen parça fonksiyonel testlerde kaçak verdi.", "why2": "Parça tedarikçiden gelmeden önce sızdırmazlık testi yapılmamış.", "why3": "Girdi kalite kontrolünde fonksiyonel test kapsamına bu parça dahil edilmemiş.", "why4": "Parçanın fonksiyonel test gerektirdiği muayene planına yansıtılmamış.", "why5": "Bu parça kodunun fonksiyonel test kriter ve yöntemi muayene planında tanımlı değildir.", "rootCause": "Bu parça kodunun fonksiyonel test kriter ve yöntemi muayene planında tanımlı değildir.", "immediateAction": "Mevcut stok gözden geçirilmeli; şüpheli parti sahaya çıkmadan önce %100 fonksiyonel test yapılmalı.", "preventiveAction": "Muayene planı güncellenerek bu parça kodu için kaçak testi zorunlu adım yapılmalı. Tedarikçiye sızdırmazlık sertifikası şartı getirilmeli."}'::jsonb, ishikawa_analysis = '{"problem": "Müşteri şikayeti üzerine incelenen parça fonksiyonel testlerde kaçak verdi.", "man": ["Kalite kontrol personeli parçanın kritikliğini fark etmeden görsel kontrolle bırakmış."], "material": ["Parçanın sızdırmazlık contaları veya hammaddesi tedarikçi tarafından değiştirilmiş olabilir."], "machine": ["Parça test ekipmanı (kaçak test standı) mevcut değil veya kapasitesi yetersiz."], "environment": ["Tedarikçi depolama/taşıma koşulları conta ömrünü olumsuz etkilemiş olabilir."], "measurement": ["Ölçüm kapsamı yetersiz; fonksiyonel test metodolojisi tanımlı değil."], "management": ["Muayene planı bu kritik parça için fonksiyonel test içermiyor."]}'::jsonb WHERE nc_number = 'DF-2026-005';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Pompa kampanası iki kritik ölçüde tolerans dışında (219,1→217,1 mm ve 15→12,5 mm).", "why1": "Pompa kampanası iki kritik ölçüde tolerans dışında (219,1→217,1 mm ve 15→12,5 mm).", "why2": "Özkan Makine bu parçayı teknik resme göre üretmemiş.", "why3": "Teknik resim revizyonu tedarikçiye ulaşmamış veya güncel resim kullanılmamış.", "why4": "Tedarikçi ile teknik resim yönetimi ve revizyon süreci resmi olarak yapılandırılmamış.", "why5": "Tedarikçiye güncel teknik resim sağlanmamış veya uygulama teyidi yapılmamış.", "rootCause": "Tedarikçiye güncel teknik resim sağlanmamış veya uygulama teyidi yapılmamış.", "immediateAction": "Şartlı kabul yerine parçanın kullanılabilirliği takip edilmeli. Parça izlenmeli.", "preventiveAction": "Teknik resim dağıtım prosedürü oluşturulmalı; tedarikçi onaylı resmin son revizyonunu kullandığını belgelemeli."}'::jsonb, ishikawa_analysis = '{"problem": "Özkan Makine — JCB 74kW Motor Pompa Kampanası ölçü hatası (şartlı kabul).", "man": ["Operatör eski teknik resmi kullanmış; revizyon duyurulmamış."], "material": ["Hammadde doğru boyutta değil veya farklı lot kullanılmış."], "machine": ["İşleme tezgahının takım aşınması veya ayar hatası."], "environment": ["Tedarikçi ortamındaki titreşim/sıcaklık takım ayarını etkilemiş olabilir."], "measurement": ["Tedarikçi son kontrol yapmıyor; muayene aleti kalibre değil."], "management": ["Teknik resim revizyon tebliği prosedürü tedarikçi ile mutabık kılınmamış."]}'::jsonb WHERE nc_number = 'DF-2026-016';
UPDATE non_conformities SET five_why_analysis = '{"problem": "12 adet konveyor burcu GKK''da şartlı kabul edildi. 5 ölçümde %100 uygunsuz.", "why1": "12 adet konveyor burcu GKK''da şartlı kabul edildi. 5 ölçümde %100 uygunsuz.", "why2": "Uzçelik üretim sonrası boyutsal teyit yapmıyor.", "why3": "Tedarikçide bu parça için bir doğrulama adımı yok.", "why4": "Kalite güvence adımları parça bazlı değil, parti bazlı ve seyrek uygulanıyor.", "why5": "Uzçelik''te bu parçaya yönelik son kontrol prosedürü tanımlı değildir.", "rootCause": "Uzçelik''te bu parçaya yönelik son kontrol prosedürü tanımlı değildir.", "immediateAction": "12 adet şartlı kabul edilen parçanın kullanımı izlenmeli; kritik ölçüler yerleşik konumda doğrulanmalı.", "preventiveAction": "Uzçelik ile yapılacak tedarikçi denetiminde kontrol planı ve kalibrasyon kayıtları incelenmeli."}'::jsonb, ishikawa_analysis = '{"problem": "Uzçelik Makine — Konveyor Burcu ölçü hatası (şartlı kabul, 12 adet).", "man": ["Operatör ölçüm yapmamış."], "material": ["Malzeme ısıl işlem sonrası boyutsal değişime uğramış olabilir."], "machine": ["Tezgah kalibrasyonu eksik veya takım aşınmış."], "environment": ["Üretim ortamı sıcaklık kontrolsüz."], "measurement": ["Tedarikçide ölçüm aleti kalibrasyon kaydı yok."], "management": ["Parça kodu bazlı kontrol talimatı yok."]}'::jsonb WHERE nc_number = 'DF-2026-017';
UPDATE non_conformities SET five_why_analysis = '{"problem": "5 adet Arka Fırça Kaldırma Borusu''nda M8 diş NOK (tüm parçalar).", "why1": "5 adet Arka Fırça Kaldırma Borusu''nda M8 diş NOK (tüm parçalar).", "why2": "Saytek üretim sırasında diş açma kalitesini kontrol etmemiş.", "why3": "Diş açma (kılavuz) adımında hata kontrolü yok.", "why4": "Saytek''in iş talimatı bu parça için diş kontrolü içermiyor.", "why5": "Saytek''in Arka Fırça Kaldırma Borusu üretim talimatında M8 diş kalite doğrulaması yer almıyor.", "rootCause": "Saytek''in Arka Fırça Kaldırma Borusu üretim talimatında M8 diş kalite doğrulaması yer almıyor.", "immediateAction": "5 adet iade. Saytek''ten düzeltilmiş parti ve kök neden raporu talep edilmeli.", "preventiveAction": "Saytek üretim talimatına M8 diş kontrol adımı (go/no-go) eklenmeli."}'::jsonb, ishikawa_analysis = '{"problem": "Saytek — Arka Fırça Kaldırma Borusu M8 diş hatası (5 adet, %100 ret).", "man": ["Operatör kılavuz diş kalitesini görmezden gelmiş."], "material": ["Boru malzemesinin sertliği belirtilen ölçüde değil, diş açma güçleşmiş."], "machine": ["Kılavuz (tap) aşınmış veya kırık; parça üretilmeye devam edilmiş."], "environment": ["Talaş birikimi diş kalitesini bozmuş."], "measurement": ["Go/no-go mastarı kullanılmıyor; diş derinliği ölçülmüyor."], "management": ["Diş kontrolü talimatı ve go/no-go mastarı kullanımı tanımlanmamış."]}'::jsonb WHERE nc_number = 'DF-2026-038';
UPDATE non_conformities SET five_why_analysis = '{"problem": "HSCK aracı konteyner kaldırırken çöp konteyner kapağı araca çarpıyor, çöp dökülemiyor veya kontrol dışı dökülüyor.", "why1": "HSCK aracı konteyner kaldırırken çöp konteyner kapağı araca çarpıyor, çöp dökülemiyor veya kontrol dışı dökülüyor.", "why2": "HSCK''nın kaldırma mekanizması bölgede kullanılan konteyner kapağı ölçüleriyle uyumsuz.", "why3": "Müşteri sahasındaki konteyner tipi/boyutu araç tasarım kriterlerinde dikkate alınmamış.", "why4": "Araç tasarımı belirli bir standart konteyner boyutuna göre yapılmış; saha diversitesi değerlendirilmemiş.", "why5": "Araç montaj/kabul testlerinde, bölgeye özgü konteyner boyutları kullanılarak senaryo testi yapılmamıştır.", "rootCause": "Araç montaj/kabul testlerinde, bölgeye özgü konteyner boyutları kullanılarak senaryo testi yapılmamıştır.", "immediateAction": "Saha müdahalesi yapılarak kaldırma yüksekliği ve açısı ayarlanmalı. Müşteriye bilgi verilmeli.", "preventiveAction": "Ar-Ge ile konteyner kapağı çarpmasını önleyecek kılavuz/limitör tasarımı değerlendirilmeli. Benzer sahalar için konteyner uyumluluk testi protokolü oluşturulmalı."}'::jsonb, ishikawa_analysis = '{"problem": "HSCK aracı — Konteyner kapağı çarpma / çöp dökme sorunu (müşteri sahası).", "man": ["Saha testleri veya kabul sürecinde farklı konteyner tipleri denenmemiş."], "material": ["Konteyner kapak geometrisi standart dışı veya farklı üretici."], "machine": ["Kaldırma mekanizması farklı kapak boyutlarına adapte edilecek şekilde ayarlanamıyor."], "environment": ["Rüzgar, kaldırma açısı gibi çevresel faktörler kapağı iterek devreye giriyor."], "measurement": ["Saha kabul testimde çarpma mesafesi ölçülmememiş."], "management": ["Müşteri tesliminden önce saha kabul testi yapılmamış veya kapsamı yetersiz."]}'::jsonb WHERE nc_number = 'DF-2026-039';
