UPDATE non_conformities SET five_why_analysis = '{"problem": "Tedarikçiden gelen radyatörde çatlak tespit edildi.", "why1": "Tedarikçiden gelen radyatörde çatlak tespit edildi.", "why2": "Radyatör temin edilmeden önce basınç testi veya görsel inceleme yapılmamış.", "why3": "Girdi kalite kontrolü kapsamında radyatöre yönelik kontrol kriteri tanımlanmamış.", "why4": "Radyatörün kritikliği göz ardı edilerek standart girdi kontrolüyle geçilmiş.", "why5": "Radyatör muayene planında çatlak, deformasyon ve basınç testi kriterleri yer almamaktadır.", "rootCause": "Radyatör muayene planında çatlak, deformasyon ve basınç testi kriterleri yer almamaktadır.", "immediateAction": "Uygun olmayan radyatör iade. Tedarikçi muayene kriterleri güncellenmeli.", "preventiveAction": "Radyatör kontrol planına basınç testi (hidrostatik) ve görsel bütünlük kontrolü eklenmelidir."}'::jsonb, ishikawa_analysis = '{"problem": "Radyatör çatlağı (tedarikçi).", "man": ["Kalite kontrol personeli radyatör kontrolünde görsel incelemeyi yeterli saymış."], "material": ["Radyatör hammaddesi/kaynak kalitesi yetersiz olabilir."], "machine": ["Basınç test stanı radyatör boyutuna uygun değil veya prosedür belirsiz."], "environment": ["Taşıma sırasında termal veya mekanik stres uygulanmış."], "measurement": ["Çatlak tahribatsız muayene (PT/MT) yapılmadan tespit edilemez; bu test uygulanmamış."], "management": ["Radyatör kabulünde sadece paket bütünlüğü kontrol edilmiş."]}'::jsonb WHERE nc_number = 'DF-2026-048';
