UPDATE non_conformities SET five_why_analysis = '{"problem": "14 adet Ön Dingil Kiti''nde hem boyutsal hem de M18x1,25 ve M8x1,5 diş hatası (tümü NOK).", "why1": "14 adet Ön Dingil Kiti''nde hem boyutsal hem de M18x1,25 ve M8x1,5 diş hatası (tümü NOK).", "why2": "Saytek Ön Dingil Kiti üretiminde hem boyutsal hem diş kontrolü yapmamış.", "why3": "Birden fazla kalite kriteri aynı anda başarısız olmuş; kök neden üretim sürecinin bütününde.", "why4": "Saytek kalite sistemi bu karmaşık parça için yetersiz kalmaktadır.", "why5": "Saytek''te Ön Dingil Kiti üretim sürecinde çok parametreli kalite kontrolü uygulanmamakta; hem boyut hem diş kalitesi doğrulanmadan sevkiyat yapılmaktadır.", "rootCause": "Saytek''te Ön Dingil Kiti üretim sürecinde çok parametreli kalite kontrolü uygulanmamakta; hem boyut hem diş kalitesi doğrulanmadan sevkiyat yapılmaktadır.", "immediateAction": "14 adet tamamen iade. Tedarikçiden kök neden analizi ve kapsamlı düzeltici faaliyet planı talep edilmeli.", "preventiveAction": "Saytek''in bu seviyedeki kalite performansı tedarikçi değerlendirme sistemine yansıtılmalı. Alternatif tedarikçi araştırılmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Saytek — Ön Dingil Kiti boyutsal ve diş hatası (14 adet, ret).", "man": ["Operatör birden fazla özelliği kontrol etmemiş."], "material": ["Malzeme sertlik seviyesi işlemeye uygun değil."], "machine": ["Tezgah takımları aşınmış; hem boyut hem diş etkilenmiş."], "environment": ["Üretim baskısı kontrol adımlarını atlatmış."], "measurement": ["Go/no-go mastarı kullanılmıyor."], "management": ["Kontrol talimatı bu parça tipi için tüm özellikleri kapsamıyor."]}'::jsonb WHERE nc_number = 'DF-2026-062';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Bağlantı milinde kritik özellik: nominal 8 mm, ölçülen 0 mm (eksik delik/işlem). Ayrıca 27 mm yerine 30 mm.", "why1": "Bağlantı milinde kritik özellik: nominal 8 mm, ölçülen 0 mm (eksik delik/işlem). Ayrıca 27 mm yerine 30 mm.", "why2": "Bir boyut tamamen sıfır çıkmış — bu boyut için işlem yapılmamış veya tamamen atlanmış.", "why3": "Üretim sürecinde bu adım için doğrulama yapılmıyor.", "why4": "İş talimatı bu kritik delik/boyut adımını içermiyor.", "why5": "Uzçelik üretim talimatında kritik boyut için ayrı bir proses adımı tanımlanmamıştır; işlem atlanmış ve kontrol edilmemiştir.", "rootCause": "Uzçelik üretim talimatında kritik boyut için ayrı bir proses adımı tanımlanmamıştır; işlem atlanmış ve kontrol edilmemiştir.", "immediateAction": "Şartlı kabul takibi zorunlu. Bu boyutsuz parçanın montajda neden olabileceği risk değerlendirilmeli.", "preventiveAction": "Uzçelik üretim talimatı acilen revize edilmeli. Kritik boyut için ayrı onay adımı tanımlanmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Uzçelik — Bağlantı mili kritik ölçü hatası (5 adet, şartlı kabul).", "man": ["Operatör veya hat sorumlusu kritik adımı atlamış."], "material": ["Hammadde bu boyutu karşılamıyor."], "machine": ["İlgili takım veya kalıp mevcut değildi."], "environment": ["Çevre faktörü katkısı düşük."], "measurement": ["Kritik boyut son kontrol kapsamı dışında."], "management": ["İş talimatında kritik delik/boyut belirtilmemiş."]}'::jsonb WHERE nc_number = 'DF-2026-075';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Motor stoklama alanı dış hava koşullarına açık durumda; uygunsuz stoklama tespit edildi.", "why1": "Motor stoklama alanı dış hava koşullarına açık durumda; uygunsuz stoklama tespit edildi.", "why2": "Motor stoklama için uygun kapalı bir alan tahsis edilmemiş.", "why3": "Depo alanı planlaması motorlar için gerekli çevre koşullarını gözetmemiş.", "why4": "Depo alan düzenleme standartları oluşturulurken motor özellikleri dikkate alınmamış.", "why5": "Depo alan planlamasında motor tipindeki hassas ekipmanlar için korumalı alan ayrılmamıştır.", "rootCause": "Depo alan planlamasında motor tipindeki hassas ekipmanlar için korumalı alan ayrılmamıştır.", "immediateAction": "Motor stoklama için kapalı alan veya branda/kapak temin edilmeli. Geçici çözüm uygulanmalı.", "preventiveAction": "Depo yerleşim planı revize edilmeli; motor tipindeki ekipmanlar için korumalı raf/sundurma alanı tahsis edilmeli. Stoklama koşulları talimatı oluşturulmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Motor stoklama alanı dış etkenlere açık ve uygunsuz.", "man": ["Depo personeli motorların dış ortama maruz kalmaması gerektiğini bilmemiş."], "material": ["Motor tipi/ağırlığı uygun bir palet/raf sistemini zorlaştırıyor."], "machine": ["Motorları koruyacak kapalı/sundurmalı alan mevcut değil."], "environment": ["Havanın nemi ve sıcaklık değişimleri motorları olumsuz etkiliyor."], "measurement": ["Motor stoklama koşulları için ölçüm/izleme yapılmıyor."], "management": ["Depolama standartları parça tipine göre segmentasyon içermiyor."]}'::jsonb WHERE nc_number = 'DF-2026-007';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Rextroth (hidrolik kumanda) ekipmanları zeminde dağınık ve uygunsuz şekilde depolanıyor.", "why1": "Rextroth (hidrolik kumanda) ekipmanları zeminde dağınık ve uygunsuz şekilde depolanıyor.", "why2": "Rextroth ekipmanları için uygun raf veya askı sistemi sağlanmamış.", "why3": "Bu ekipmanların depolanmasına ilişkin talimat veya zimmet takibi yok.", "why4": "Depo stoklama prosedürü hassas hidrolik bileşenleri kapsamıyor.", "why5": "Depo stoklama talimatında Rextroth tipi hassas ekipmanlar için uygun depolama yöntemi tanımlanmamıştır.", "rootCause": "Depo stoklama talimatında Rextroth tipi hassas ekipmanlar için uygun depolama yöntemi tanımlanmamıştır.", "immediateAction": "Mevcut Rextroth ekipmanları uygun palet/kasa üzerine alınmalı; zemin teması kesilmeli.", "preventiveAction": "Depo talimatına Rextroth tipi ekipmanlar için özel stoklama yöntemi eklenmeli. Raf/askı sistemi temin planı yapılmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Rextroth ekipmanları zeminde ve uygunsuz depolanıyor.", "man": ["Depo personeli bu ekipmanların uygun stoklama koşullarını bilmiyor."], "material": ["Rextroth ekipmanları ağır ve hacimli; zeminde bırakılmış."], "machine": ["Uygun raf/ask sistemi fiziksel olarak mevcut değil."], "environment": ["Zemine bırakılan ekipmanlar nem ve darbeden etkileniyor."], "measurement": ["Ekipman durumu ve konumu kayıt altına alınmıyor."], "management": ["Talimat veya prosedürde bu parça tipi için stoklama standardı yok."]}'::jsonb WHERE nc_number = 'DF-2026-008';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Ax sisteminde parti numarası bazlı kayıt tutulurken fiziki depoda parti ayrımı yapılmıyor.", "why1": "Ax sisteminde parti numarası bazlı kayıt tutulurken fiziki depoda parti ayrımı yapılmıyor.", "why2": "Depo personeli fiziki ürünleri Ax''taki parti yapısına göre ayırmıyor.", "why3": "Parti numarası bazlı ayrım yapılması gerektiği konusunda yeterli eğitim ve talimat yok.", "why4": "Depo prosedürü, sistemdeki parti yapısının fiziki depoya yansıtılmasını şart koşmuyor.", "why5": "Depo stoklama talimatı, Ax sistemindeki parti numarasının fiziksel alanda da birebir uygulanmasını zorunlu kılmamaktadır.", "rootCause": "Depo stoklama talimatı, Ax sistemindeki parti numarasının fiziksel alanda da birebir uygulanmasını zorunlu kılmamaktadır.", "immediateAction": "Mevcut ürünler yeniden parti bazlı bölümlere ayrılmalı. Etiketleme yapılmalı.", "preventiveAction": "Depo talimatı güncellenmeli: parti numarası bazlı stoklama zorunlu yapılmalı. Ax girişi ile etiket eşleştirme prosedürü oluşturulmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Ax sisteminde parti no ayrımı yapılmaması.", "man": ["Personel parti ayrımı konusunda eğitim almamış."], "material": ["Farklı partiler aynı raf/alanda yer alıyor; karışmaya uygun ortam."], "machine": ["Depo fiziksel alanında parti bazlı bölümlendirme yok; etiketleme eksik."], "environment": ["Parti ayrımını zorlaştıran depo düzeni."], "measurement": ["Ax''taki parti ile fiziksel ürün eşleştirmesi doğrulanmıyor."], "management": ["Ax sistemi ile fiziksel depo uyumu prosedüre bağlanmamış."]}'::jsonb WHERE nc_number = 'DF-2026-010';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Ax kaydında ''0 Genel Konumu''nda görünen ürünler (hatalı, bekleyen, teslim alınmamış) fiziksel depoda bulunmuyor.", "why1": "Ax kaydında ''0 Genel Konumu''nda görünen ürünler (hatalı, bekleyen, teslim alınmamış) fiziksel depoda bulunmuyor.", "why2": "0 Genel Konumu soyut bir Ax kategorisi olarak kullanılıyor, fiziksel alan tanımlanmamış.", "why3": "Bu kategoriye giren ürünlerin fiziksel konumu belirsiz; karantina alanı oluşturulmamış.", "why4": "Depo prosedüründe 0 konumundaki ürünler için fiziksel alan ve izleme tanımlanmamış.", "why5": "Ax sisteminde ''0 Genel Konumu'' kategorisindeki ürünler için fiziksel bir karantina alanı ve izleme prosedürü yoktur.", "rootCause": "Ax sisteminde ''0 Genel Konumu'' kategorisindeki ürünler için fiziksel bir karantina alanı ve izleme prosedürü yoktur.", "immediateAction": "0 Genel Konumu ürünleri için fiziksel karantina alanı oluşturulmalı; mevcut ürünler tespit edilmeli.", "preventiveAction": "Ax''ta 0 konumuna giren her ürün için fiziksel karantina kuralı işlemselleştirilmeli. Depo talimatı güncellenmeli."}'::jsonb, ishikawa_analysis = '{"problem": "Ax''ta 0 Genel Konumunda bulunan ürünler — fiziksel karşılığı yok.", "man": ["Personel bu kategorinin ne anlama geldiğini bilmiyor."], "material": ["Hatalı ve bekleyen ürünler diğer ürünlerle karışabilir."], "machine": ["Fiziksel karantina alanı yok."], "environment": ["Karantina uygulanmazsa saha koşulları ürünü olumsuz etkiler."], "measurement": ["0 konumundaki ürünler takip edilemiyor; kayıplar fark edilemiyor."], "management": ["Prosedürde bu kategori için fiziksel tanım eksik."]}'::jsonb WHERE nc_number = 'DF-2026-011';
