UPDATE non_conformities SET five_why_analysis = '{"problem": "Uygunsuz ürünler, üretim veya hat sorumlusu tarafından sapma talebi hazırlanmadan alınıp kullanılıyor.", "why1": "Uygunsuz ürünler, üretim veya hat sorumlusu tarafından sapma talebi hazırlanmadan alınıp kullanılıyor.", "why2": "Üretim personeli sapma talebi prosedürünü bilmiyor veya uygulamıyor.", "why3": "Sapma talebi sürecinin işlevselliği üretim hızına feda ediliyor.", "why4": "Kalite kontrol sapma talebini zorunlu kılacak bir süreç güvencesi uygulamıyor.", "why5": "Uygunsuz ürün tespitinde üretim personelinin sapma talebi prosedürünü uygulamasını zorlayan bir sistem/kontrol mekanizması yoktur.", "rootCause": "Uygunsuz ürün tespitinde üretim personelinin sapma talebi prosedürünü uygulamasını zorlayan bir sistem/kontrol mekanizması yoktur.", "immediateAction": "Uygunsuz ürün depolarının fiziksel karantina ile hat arasında net sınır belirlenmeli.", "preventiveAction": "Üretim personeline sapma talebi prosedürü yeniden eğitim verilmeli. Hat sorumlusu kontrolünde uygunsuz ürün izin mekanizması uygulamaya alınmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Sapma talebi hazırlanmadan uygunsuz ürün kullanımı.", "man": ["Personel uygunsuz ürünü kullanmanın hızlı bir çözüm olduğunu düşünüyor."], "material": ["Uygunsuz ürünler karantina alanı yerine üretim hattına bırakılıyor."], "machine": ["Sapma formu doldurmak için zaman veya araç yokluğu."], "environment": ["Zaman baskısı sapma prosedürünü atlatmayı teşvik ediyor."], "measurement": ["Uygunsuz ürün kaydı tutulmadığından sapma takibi yapılamıyor."], "management": ["Sapma prosedürü yeterince duyurulmamış veya eğitim verilmemiş."]}'::jsonb WHERE nc_number = 'DF-2026-020';
UPDATE non_conformities SET five_why_analysis = '{"problem": "55 KW Perkins motorlar için 190''lık pompa zorunlu MDB yayınlanmış, üretim buna rağmen 160''lık pompa kullanmaya devam etmiştir.", "why1": "55 KW Perkins motorlar için 190''lık pompa zorunlu MDB yayınlanmış, üretim buna rağmen 160''lık pompa kullanmaya devam etmiştir.", "why2": "MDB duyurusu üretim hattına etkin biçimde iletilmemiş.", "why3": "Üretim sorumlusu MDB''yi okuyup uygulamayı sağlamamış.", "why4": "MDB yayınlama süreci üretim departmanının bilgilendirilmesini garanti etmiyor.", "why5": "MDB yayınlama prosedürü, ilgili üretim hatlarına zorunlu onay/imzalatma adımı içermediğinden değişiklik fiilen uygulanmamıştır.", "rootCause": "MDB yayınlama prosedürü, ilgili üretim hatlarına zorunlu onay/imzalatma adımı içermediğinden değişiklik fiilen uygulanmamıştır.", "immediateAction": "Stokta kalan 160''lık pompalar kaldırılmalı veya etiketlenmeli. Bu parça kodu kontrol planına eklenmeli.", "preventiveAction": "MDB yayın prosedürü güncellenmeli: İlgili hat sorumlusunun okudu-anladı imzası ve eski parça iadesi adımı eklenmeli."}'::jsonb, ishikawa_analysis = '{"problem": "55 KW Perkins Motor — MDB''ye rağmen 160''lık pompa kullanımı.", "man": ["Hat personeli yanlış pompa stoğundan almaya devam etmiş."], "material": ["Stokta 160''lık pompalar kalmış; personel eskiyi kullanmış."], "machine": ["Stok alanında 160''lık pompalar hala erişilebilir konumda."], "environment": ["Acele üretim baskısı MDB uyumunu geciktirmiş."], "measurement": ["160''lık pompa yerine 190''lık kullanılıp kullanılmadığı kontrol planında doğrulanmıyor."], "management": ["MDB dağıtım akışı üretim hattına tebligat mekanizması içermiyor."]}'::jsonb WHERE nc_number = 'DF-2026-024';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Ordu üst yapıdan sökülen Fan Gövdesi Kaynaklı Komple kullanıma uygun bulunmayarak hurdaya ayrıldı. Araç bazlı hurda ağırlığı hedefin (20 kg/araç) üzerinde (31,5 kg/araç).", "why1": "Ordu üst yapıdan sökülen Fan Gövdesi Kaynaklı Komple kullanıma uygun bulunmayarak hurdaya ayrıldı. Araç bazlı hurda ağırlığı hedefin (20 kg/araç) üzerinde (31,5 kg/araç).", "why2": "Fan gövdesi sökümde hasar gördü veya montaj öncesi uygunsuz durumda geldi.", "why3": "Söküm sırasında fan gövdesinin korunmasına yönelik talimat/prosedür yok.", "why4": "Fan gövdesinin söküm ve yeniden montaj uygunluğu değerlendirilmiyor.", "why5": "Söküm prosedürü, fan gövdesi kaynaklı kompleksin demontajında hasar önleme adımlarını içermemektedir.", "rootCause": "Söküm prosedürü, fan gövdesi kaynaklı kompleksin demontajında hasar önleme adımlarını içermemektedir.", "immediateAction": "Hurda kayıt altına alınmalı; hurda analiz raporu dosyalanmalı.", "preventiveAction": "Fan gövdesi demontaj talimatı hazırlanmalı. Söküm sırasında parçanın korunması için fikstür ve hassas söküm prosedürü oluşturulmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Fan gövdesi kaynaklı komple — hurda (KDM 80).", "man": ["Söküm yapan personel parçayı hasarsız sökmek için gerekli yöntemi bilmiyor."], "material": ["Fan gövdesi ağır ve hassas; yanlış söküm geometri bozukluğuna neden oluyor."], "machine": ["Uygun söküm takımları ve fikstür yok."], "environment": ["Söküm sırasında çevresel faktörler (diğer parçaların çarpması vb.) hasara katkıda bulunuyor."], "measurement": ["Söküm sonrası parça kalitesi kontrol edilmiyor."], "management": ["Demontaj talimatı bu parça için hazırlanmamış."]}'::jsonb WHERE nc_number = 'DF-2026-031';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Depo birimi tarafından açılan yetkisiz sipariş (bkz. DF-2026-080), Genel Müdür tarafından yasaklanmış olmasına rağmen onaylanmıştır.", "why1": "Depo birimi tarafından açılan yetkisiz sipariş (bkz. DF-2026-080), Genel Müdür tarafından yasaklanmış olmasına rağmen onaylanmıştır.", "why2": "Onay veren kişi siparişin yetkisiz olduğunu fark etmemiştir.", "why3": "Sipariş onay sürecinde sipariş açan birimin yetkisi kontrol edilmemektedir.", "why4": "Ax onay akışı sipariş yetkisi matrisiyle entegre değildir.", "why5": "Sipariş onay mekanizması, sipariş talep edenin yetki profilini ve bu parça kodu için izin durumunu doğrulayan bir kontrol içermemektedir.", "rootCause": "Sipariş onay mekanizması, sipariş talep edenin yetki profilini ve bu parça kodu için izin durumunu doğrulayan bir kontrol içermemektedir.", "immediateAction": "Onayı geri alarak siparişi iptal etmek veya yetkili kişiye yönlendirmek gerekmektedir.", "preventiveAction": "Ax sisteminde kanban dışı siparişler için açık yetki matrisi oluşturulmalı; onay akışına ''Sipariş Yetkisi Teyit'' adımı eklenmeli."}'::jsonb, ishikawa_analysis = '{"problem": "Yetkisiz depo siparişinin üst yönetim onayından geçmesi.", "man": ["Onaylayan kişi siparişin kaynağını/yetkisini sorgulamadan onaylamış."], "material": ["Parça kodu veya sipariş formu kaynağı belirsiz bırakılmış."], "machine": ["Ax sisteminde yetki kontrolü otomatik değil; manüel incelemeye bırakılmış."], "environment": ["Çevre faktörü katkısı yok."], "measurement": ["Ax onay ekranı yetki ihlali uyarısı vermiyor."], "management": ["Onay prosedürü yetki teyit adımı içermiyor."]}'::jsonb WHERE nc_number = 'DF-2026-081';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Almaksan firmasından gelen HSCK araçlarında sevkiyat sırasında arka kapak emniyet direğinde ezilmeler tespit edildi.", "why1": "Almaksan firmasından gelen HSCK araçlarında sevkiyat sırasında arka kapak emniyet direğinde ezilmeler tespit edildi.", "why2": "Sevkiyat sırasında emniyet direği bölgesine darbe gelmektedir.", "why3": "Sevkiyat ambalajlama/sabitleme yöntemi emniyet direğini korumak üzere tasarlanmamıştır.", "why4": "Almaksan sevkiyat için özel koruma gerekliliklerini bilmemekte veya uygulamıyor.", "why5": "Almaksan ile mutabık kılınan sevkiyat teknik şartnamesinde emniyet direği bölgesine özel koruma zorunluluğu tanımlanmamıştır.", "rootCause": "Almaksan ile mutabık kılınan sevkiyat teknik şartnamesinde emniyet direği bölgesine özel koruma zorunluluğu tanımlanmamıştır.", "immediateAction": "Almaksan''a ezilme bildirilmeli. Mevcut ezik araç onarılmalı veya revize edilmeli.", "preventiveAction": "Almaksan sevkiyat şartnamesine emniyet direği bölgesi için zorunlu koruyucu eleman eklenmeli. Düzenli sevkiyat denetimi planlanmalı."}'::jsonb, ishikawa_analysis = '{"problem": "Almaksan HSCK — Arka kapak emniyet direğinde ezilme (sevkiyat uygunsuzluğu).", "man": ["Almaksan personeli ezilme riskini görmezden gelmiş veya bilmemiş."], "material": ["Emniyet direği yüksekliği ve çevresinde diğer yük veya bağlantı noktaları riske açık."], "machine": ["Emniyet direğini koruyacak köpük/kaplin veya bariyer yok."], "environment": ["Taşıma titreşimi ve darbesi ezilmeye neden oluyor."], "measurement": ["Sevkiyat sonrası ezilme ölçülüp kayıt altına alınmıyor."], "management": ["Sevkiyat şartnamesinde hassas bölge listesi yok."]}'::jsonb WHERE nc_number = 'DF-2026-045';
UPDATE non_conformities SET five_why_analysis = '{"problem": "Kazan kapalıyken açılmasını engelleyen sistem aktif edilmemiş. SSH sahasında müşteri şikayeti. Yazılım güncellemesiyle kapatılmış.", "why1": "Kazan kapalıyken açılmasını engelleyen sistem aktif edilmemiş. SSH sahasında müşteri şikayeti. Yazılım güncellemesiyle kapatılmış.", "why2": "Yazılım özelliği test ve doğrulama aşamasında aktifleştirilmemiş.", "why3": "AGA6000 üretim doğrulama kontrol listesi bu güvenlik yazılım özelliğini içermiyordu.", "why4": "Yazılım güvenlik özellikleri kontrol planıyla entegre edilmemiş.", "why5": "AGA6000 üretim son kontrol prosedüründe yazılım güvenlik kilitleri doğrulama adımı tanımlı değildir.", "rootCause": "AGA6000 üretim son kontrol prosedüründe yazılım güvenlik kilitleri doğrulama adımı tanımlı değildir.", "immediateAction": "Yazılım güncellemesi tüm AGA6000''lere uygulanmış (Kapatıldı).", "preventiveAction": "AGA6000 üretim son kontrol listesine kazan kilidi doğrulama adımı kalıcı olarak eklenmeli. Yazılım güvenlik özellik testi standart hale getirilmeli."}'::jsonb, ishikawa_analysis = '{"problem": "AGA6000 — Kazan kilitleme sistemi aktif edilmedi (Ar-Ge, kapatıldı).", "man": ["Yazılım geliştirici bu özelliğin üretimde aktif edilmesi gerektiğini varsaymış."], "material": ["Yazılım sürüm yönetimi bu özelliğin aktif durumunu takip etmemiş."], "machine": ["Test cihazı veya ortamı bu senaryoyu test etmemiş."], "environment": ["Çevre faktörü katkısı yok."], "measurement": ["Yazılım test metodolojisi güvenlik kilidi senaryolarını içermemiş."], "management": ["Üretim kontrol planı yazılım özellik testini kapsamamış."]}'::jsonb WHERE nc_number = 'DF-2026-051';
